{"file_path":"/home/user/workspace/app/actions.ts","content":""use server";

import { revalidateTag } from "next/cache";
import { redirect } from "next/navigation";
import { createPost } from "@/lib/posts";

export async function createPostAction(formData: FormData) {
  const title = formData.get("title") as string;
  const content = formData.get("content") as string;

  if (!title || !content) {
    throw new Error("Title and content are required");
  }

  // Persist the new post to the data store
  createPost(title, content);

  // Invalidate the "posts" cache tag so the next page load
  // re-fetches data instead of serving stale cached content.
  revalidateTag("posts");

  // Redirect ensures the page is re-rendered with fresh data
  // from the server — the user never sees stale cached posts.
  redirect("/");
}
"}

